public class Example1 {
  public void foo() {
    // violation below 'Expression lambdas are preferred over single-line block lambdas.'
    Runnable a = () -> { System.out.println("hello"); };

    // violation below 'Expression lambdas are preferred over single-line block lambdas.'
    Function<Integer, Integer> b = x -> { return x + 1; };

    // OK - expression lambda (already correct)
    Runnable c = () -> System.out.println("hello");

    // OK - multi-line block lambda (can't be collapsed)
    Runnable d = () -> {
        System.out.println("hello");
    };

    // OK - void return (can't become expression lambda)
    Runnable e = () -> { return; };

    // OK - multi-statement block (can't become expression lambda)
    Runnable f = () -> { a(); b(); };
  }
}
